  ('dietitian-moex-06966', 'dietitian', 'dietitian-moex-103-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '關於驗收之敘述，下列何者錯誤？ 驗收可由採購人員擔任   驗收區應準備秤量器具 驗收區宜接近前處理區   驗收不合格的貨品可以拒收', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "669e3f56ea31", "answer_pdf_sha1": "44b27236efc3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
